  if (width <= 0 || height <= 0) {
    return false;
  }
  if (!range->prepare_read(static_cast<uint64_t>(width) * height)) {
    return false;
  }
  if (!image->add_plane(channel, width, height, bit_depth)) {
    return false;
  }
