        int num = exif_mnote_data_count(mn);

        /* Loop through all MakerNote tags */
        for (int i=0; i < num; ++i) {
            char buf[1024];
            exif_mnote_data_get_value(mn, i, buf, sizeof(buf));
        }
    }
